        function collectTagSubtreeIds(rootId) {
            const ids = [];
            const queue = [rootId];
            const seen = new Set();
            while (queue.length) {
                const current = queue.shift();
                if (seen.has(current)) {
                    continue;
                }
                seen.add(current);
                ids.push(current);
                const children = tagChildrenMap.value.get(current) ?? [];
                for (const child of children) {
                    queue.push(child.id);
